# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests
import json

class KongConfig:
    def __init__(self, admin_url):
        self.admin_url = admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})
    
    def create_service(self, service_name, url, protocol='http'):
        """Create a service in Kong"""
        service_data = {
            'name': service_name,
            'url': url,
            'protocol': protocol
        }
        response = self.session.post(f'{self.admin_url}/services', json=service_data)
        return response.json()
    
    def create_route(self, service_id, route_name, hosts=None, paths=None, methods=None):
        """Create a route for a service"""
        route_data = {
            'name': route_name,
            'service': {'id': service_id}
        }
        
        if hosts:
            route_data['hosts'] = hosts
        if paths:
            route_data['paths'] = paths
        if methods:
            route_data['methods'] = methods
            
        response = self.session.post(f'{self.admin_url}/routes', json=route_data)
        return response.json()
    
    def create_upstream(self, upstream_name, algorithm='roundrobin'):
        """Create an upstream"""
        upstream_data = {
            'name': upstream_name,
            'algorithm': algorithm
        }
        response = self.session.post(f'{self.admin_url}/upstreams', json=upstream_data)
        return response.json()
    
    def create_target(self, upstream_id, target, port=8000):
        """Create a target for an upstream"""
        target_data = {
            'target': target,
            'port': port
        }
        response = self.session.post(f'{self.admin_url}/upstreams/{upstream_id}/targets', json=target_data)
        return response.json()
    
    def attach_upstream_to_service(self, service_id, upstream_name):
        """Attach an upstream to a service"""
        service_data = {
            'name': service_id,
            'upstream': {'name': upstream_name}
        }
        response = self.session.put(f'{self.admin_url}/services/{service_id}', json=service_data)
        return response.json()

# Example usage
if __name__ == "__main__":
    kong = KongConfig("http://localhost:8001")
    
    # Create a service
    service = kong.create_service("my-service", "http://httpbin.org")
    print("Service created:", service)
    
    # Create a route for the service
    route = kong.create_route(service['id'], "my-route", hosts=["example.com"], paths=["/api"])
    print("Route created:", route)
    
    # Create an upstream
    upstream = kong.create_upstream("my-upstream")
    print("Upstream created:", upstream)
    
    # Create targets for the upstream
    target1 = kong.create_target(upstream['id'], "127.0.0.1", 8001)
    target2 = kong.create_target(upstream['id'], "127.0.0.1", 8002)
    print("Targets created:", target1, target2)